import os
from flask import send_file

app = Flask(__name__)

@app.route('/uploads/<filename>')
def serve_static(filename):
    filepath = os.path.join('uploads', filename)
    if not os.path.exists(filepath):
        return 'File not found', 404
    return send_file(filepath)